let rec fact n =
  if n = 0 then 1
  else n * fact (n - 1)

let fact_tr n =
  let rec aux n acc =
    if n = 0 then acc
    else aux (n - 1) (n * acc)
  in
  aux n 1

let () =
  Printf.printf "fact 6 = %d\n" (fact 6);    (* 720 *)
  Printf.printf "fact_tr 6 = %d\n" (fact_tr 6) (* 720 *)

