let fact_imp n =
  let result = ref 1 in
  let i = ref 1 in
  while !i <= n do
    result := !result * !i;
    i := !i + 1
  done;
  !result

let sum_imp lst =
  let total = ref 0 in
  List.iter (fun x -> total := !total + x) lst;
  !total

let () =
  Printf.printf "5! = %d\n" (fact_imp 5);         (* 120 *)
  Printf.printf "sum = %d\n" (sum_imp [1;2;3;4;5]) (* 15 *)
